const SCRAPED_SAINTS: Record<number, typeof CALENDAR_2026> = {
  2026: CALENDAR_2026,
};

/**
 * Get saint/feast info for a given date and Easter.
 * Uses real scraped data for years where it's available.
 * Falls back to MOVEABLE_FEASTS then FIXED_SAINTS for other years.
 */
export function getSaintInfo(
  date: Date,
  easter: Date
): { name: string; description: string; isFeast: boolean } {
  // Use scraped data for years where we have it
  const yearData = SCRAPED_SAINTS[date.getFullYear()];
  if (yearData) {
    const key = `${date.getMonth() + 1}-${date.getDate()}`;
    const entry = yearData[key];
    if (entry) {
      return { name: entry.saint, description: "", isFeast: entry.isFeast };
    }
  }

  // Calculate days from Easter
  const msEaster = Date.UTC(easter.getFullYear(), easter.getMonth(), easter.getDate());
  const msDate = Date.UTC(date.getFullYear(), date.getMonth(), date.getDate());
  const diff = Math.round((msDate - msEaster) / 86400000);

  // Check moveable feasts first
  if (MOVEABLE_FEASTS[diff]) {
    return MOVEABLE_FEASTS[diff];
  }

  // Fall back to fixed saints
  const key = `${date.getMonth() + 1}-${date.getDate()}`;
  if (FIXED_SAINTS[key]) {
    return FIXED_SAINTS[key];
  }

  return {
    name: "Непознат светец",
    description: "Денот е без посебно прославување.",
    isFeast: false,
  };
}
